import { ipcMain } from 'electron';
import { randomUUID } from 'crypto';
import fs from 'fs';
import path from 'path';
import os from 'os';
import {
  IPC_CHANNELS,
  CreateServerSchema,
  UpdateServerSchema,
  ServerIdSchema,
  ReorderServersSchema,
  ApiResult,
} from './types';
import { queries } from '../db';
import { CredentialVault } from '../services/CredentialVault';
import { licenseService } from '../services/LicenseService';
import { provisioningService } from '../services/ProvisioningService';
import { sshService } from '../services/SSHService';
import type { Server } from '../db';

const vault = new CredentialVault();

// Geolocation data from ip-api.com
interface GeolocationData {
  status: string;
  country?: string;
  countryCode?: string;
  region?: string;
  regionName?: string;
  city?: string;
  zip?: string;
  lat?: number;
  lon?: number;
  timezone?: string;
  isp?: string;
  org?: string;
  as?: string;
  query?: string;
}

async function fetchGeolocationViaSSH(serverId: string): Promise<GeolocationData | null> {
  try {
    // Execute curl command on the VPS to get its own geolocation
    const result = await sshService.executeCommand(serverId, 'curl -s ip-api.com/json');

    if (!result.stdout || result.stdout.trim().length === 0) {
      console.error('Failed to fetch geolocation: Empty response from server');
      return null;
    }

    const parsed = JSON.parse(result.stdout.trim()) as GeolocationData;

    if (parsed.status === 'success') {
      return parsed;
    } else {
      console.error('Geolocation API returned failure status:', parsed);
      return null;
    }
  } catch (error) {
    console.error('Failed to fetch geolocation via SSH:', error);
    return null;
  }
}

export function registerServerHandlers() {
  // Get all servers
  ipcMain.handle(IPC_CHANNELS.SERVERS_GET_ALL, async (): Promise<ApiResult<Server[]>> => {
    try {
      const servers = queries.getAllServers();
      return { success: true, data: servers };
    } catch (error) {
      console.error('Error getting servers:', error);
      return { success: false, error: String(error) };
    }
  });

  // Get server by ID
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_GET_BY_ID,
    async (_event, input): Promise<ApiResult<Server | null>> => {
      try {
        const { id } = ServerIdSchema.parse(input);
        const server = queries.getServerById(id);
        return { success: true, data: server || null };
      } catch (error) {
        console.error('Error getting server:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Create server
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_CREATE,
    async (_event, input): Promise<ApiResult<Server>> => {
      try {
        const validated = CreateServerSchema.parse(input);

        const limitCheck = licenseService.canAddServer();
        if (!limitCheck.allowed) {
          const message =
            limitCheck.reason ||
            `Free trial allows up to ${limitCheck.max ?? 0} server(s). Activate a license to add more.`;
          return { success: false, error: message };
        }

        // Encrypt the secret
        const encryptedSecret = await vault.encrypt(validated.auth.value);

        const server: Omit<Server, 'created_at' | 'updated_at'> = {
          id: randomUUID(),
          name: validated.name,
          host: validated.host,
          port: validated.port,
          auth_type: validated.auth.type,
          username: validated.username,
          encrypted_secret: encryptedSecret,
          status: 'pending',
          last_check_in: Date.now(),
          display_order: null, // Will be auto-assigned by createServer
          packages_installed: 0, // Not checked yet
          packages_checked_at: null, // Not checked yet
          country_code: null, // Will be fetched on first access
          org: null, // Will be fetched on first access
          timezone: null, // Will be fetched on first access
          key_path: validated.keyPath ?? null, // Path to script-generated SSH key for cleanup
        };

        queries.createServer(server);
        const created = queries.getServerById(server.id);

        if (!created) {
          throw new Error('Failed to create server');
        }

        // Background check: Ensure essential packages are installed on the new server
        provisioningService.ensureEssentialPackages(server.id).catch((error) => {
          console.warn(`[ServerCreate] Background package check failed for ${server.id}:`, error);
          // Don't fail server creation if background check fails
        });

        return { success: true, data: created };
      } catch (error) {
        console.error('Error creating server:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Update server
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_UPDATE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id, updates } = UpdateServerSchema.parse(input);
        const { auth, keyPath, ...rest } = updates;
        const preparedUpdates: Partial<Server> = { ...rest };

        if (auth) {
          const encryptedSecret = await vault.encrypt(auth.value);
          preparedUpdates.auth_type = auth.type;
          preparedUpdates.encrypted_secret = encryptedSecret;
        }

        if (keyPath !== undefined) {
          preparedUpdates.key_path = keyPath ?? null;
        }

        queries.updateServer(id, preparedUpdates);
        return { success: true };
      } catch (error) {
        console.error('Error updating server:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Delete server
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_DELETE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id } = ServerIdSchema.parse(input);

        // Get server to check for key_path before deletion
        const server = queries.getServerById(id);

        // Close SSH connection for this server if exists
        try {
          await sshService.disconnect(id);
          console.log(`Closed SSH connection for deleted server: ${id}`);
        } catch (sshError) {
          // Log but don't fail the deletion if SSH disconnect fails
          console.warn(`Failed to close SSH connection for server ${id}:`, sshError);
        }

        // Clean up script-generated SSH key if exists
        if (server?.key_path) {
          const allowedDir = path.join(os.homedir(), '.ssh', 'servercompass');
          const resolvedPath = path.resolve(server.key_path);
          const resolvedAllowedDir = path.resolve(allowedDir);

          // Security: Only delete keys from the allowed directory
          if (resolvedPath.startsWith(resolvedAllowedDir + path.sep)) {
            try {
              // Delete private key
              if (fs.existsSync(resolvedPath)) {
                fs.unlinkSync(resolvedPath);
                console.log(`[ServerDelete] Cleaned up private key: ${resolvedPath}`);
              }
              // Delete public key
              const pubKeyPath = `${resolvedPath}.pub`;
              if (fs.existsSync(pubKeyPath)) {
                fs.unlinkSync(pubKeyPath);
                console.log(`[ServerDelete] Cleaned up public key: ${pubKeyPath}`);
              }
            } catch (keyError) {
              // Log but don't fail deletion if key cleanup fails
              console.warn(`[ServerDelete] Failed to clean up SSH key for server ${id}:`, keyError);
            }
          } else {
            console.warn(`[ServerDelete] Skipped key cleanup - path outside allowed directory: ${server.key_path}`);
          }
        }

        // Delete server from database
        queries.deleteServer(id);
        return { success: true };
      } catch (error) {
        console.error('Error deleting server:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Reorder servers
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_REORDER,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverIds } = ReorderServersSchema.parse(input);
        queries.reorderServers(serverIds);
        return { success: true };
      } catch (error) {
        console.error('Error reordering servers:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Update server geolocation
  ipcMain.handle(
    IPC_CHANNELS.SERVERS_UPDATE_GEOLOCATION,
    async (_event, input): Promise<ApiResult<{ countryCode: string | null; org: string | null; timezone: string | null }>> => {
      try {
        const { id } = ServerIdSchema.parse(input);
        const server = queries.getServerById(id);

        if (!server) {
          return { success: false, error: 'Server not found' };
        }

        // Only fetch if not already set
        if (server.country_code && server.org && server.timezone) {
          return {
            success: true,
            data: {
              countryCode: server.country_code,
              org: server.org,
              timezone: server.timezone
            }
          };
        }

        // Fetch geolocation data via SSH (execute curl on the VPS)
        const geoData = await fetchGeolocationViaSSH(id);

        if (geoData && geoData.countryCode && geoData.org) {
          // Update the server with geolocation data
          queries.updateServer(id, {
            country_code: geoData.countryCode,
            org: geoData.org,
            timezone: geoData.timezone ?? null,
          });

          return {
            success: true,
            data: {
              countryCode: geoData.countryCode,
              org: geoData.org,
              timezone: geoData.timezone ?? null
            }
          };
        }

        return {
          success: true,
          data: {
            countryCode: null,
            org: null,
            timezone: null
          }
        };
      } catch (error) {
        console.error('Error updating server geolocation:', error);
        return { success: false, error: String(error) };
      }
    }
  );
}
